const buildActivityHeadcountDetails = async (from, to) => {
    // Always use the client scan. It resolves each attendee's entity, which is
    // what lets us (a) split Customer vs Prospect into separate buckets and
    // (b) reclassify a prospect who has since become a customer OUT of the
    // prospect bucket (no double reporting). The report_activity_headcount_details
    // RPC returns only display_name + type, so it can't support that entity-level
    // dedup — hence it's intentionally bypassed for this drill-down.
    return _buildActivityHeadcountDetailsLegacy(from, to);
};

const _buildActivityHeadcountDetailsLegacy = async (from, to) => {
    const activities = await _reportActsInRange(from, to, '_buildActivityHeadcountDetailsLegacy');
    const [allAttendees, events, prospects, customers, users] = await Promise.all([
        AppDataStore.getAll('event_attendees'),
        AppDataStore.getAll('events'),
        AppDataStore.getAll('prospects'),
        AppDataStore.getAll('customers'),
        AppDataStore.getAll('users')
    ]);
    const actMap = {}; activities.forEach(a => { actMap[a.id] = a; });
    const eventMap = {}; events.forEach(e => { eventMap[e.id] = e; });
    const prospMap = {}; prospects.forEach(p => { prospMap[p.id] = p; });
    const custMap = {}; customers.forEach(c => { custMap[c.id] = c; });
    const userMap = {}; users.forEach(u => { userMap[u.id] = u; });

    // Double-report guard (mirrors getPeopleMet): every prospect that has already
    // become a customer — via the conversion FK, the prospect's status, or a
    // name/phone match to an existing customer — is counted under Customer here,
    // never again under Prospect.
    const convertedProspectIds = new Set();
    customers.forEach(c => { if (c.converted_from_prospect_id != null) convertedProspectIds.add(String(c.converted_from_prospect_id)); });
    prospects.forEach(p => { if (p.status === 'converted') convertedProspectIds.add(String(p.id)); });
    const _normName = (s) => String(s || '').toLowerCase().replace(/\s+/g, ' ').trim();
    const _phoneKey = (s) => { const d = String(s || '').replace(/\D/g, ''); return d.length >= 7 ? d.slice(-8) : ''; };
    const custNameKeys = new Set();
    const custPhoneKeys = new Set();
    customers.forEach(c => { const nk = _normName(c.full_name); if (nk) custNameKeys.add(nk); const pk = _phoneKey(c.phone); if (pk) custPhoneKeys.add(pk); });
    const _matchesCustomer = (name, phone) => {
        const nk = _normName(name); const pk = _phoneKey(phone);
        return (nk && custNameKeys.has(nk)) || (pk && custPhoneKeys.has(pk));
    };

    const customerRows = [];
    const prospectRows = [];
    const agentRows = [];
    const byEvent = {};

    for (const att of allAttendees) {
        if (!att.attended && att.attendance_status !== 'Attended') continue;
        const act = actMap[att.activity_id];
        const date = act?.activity_date || '';
        if (date < from || date > to) continue;
        if (!_recInMarket(act || {})) continue;
        const entityId = att.entity_id || att.attendee_id;
        if (_visibleUserIds !== 'all') {
            let agentId;
            if (att.attendee_type === 'agent') {
                agentId = entityId;
            } else if (att.attendee_type === 'customer') {
                agentId = custMap[entityId]?.responsible_agent_id;
            } else {
                agentId = prospMap[entityId]?.responsible_agent_id;
            }
            // Normalize both sides to String (matches the other visibility filters in
            // this file) — _visibleUserIds and the resolved agentId can differ in type
            // (number vs string), which would wrongly drop rows on a raw .includes.
            if (!_visibleUserIds.map(String).includes(String(agentId))) continue;
        }

        const ev = eventMap[att.event_id];
        const eventTitle = ev?.event_title || ev?.title || `Event #${att.event_id}`;

        if (att.attendee_type === 'agent') {
            const name = userMap[entityId]?.full_name || att.entity_name || '—';
            agentRows.push([date, eventTitle, name]);
        } else if (att.attendee_type === 'customer') {
            const name = custMap[entityId]?.full_name || att.entity_name || '—';
            customerRows.push([date, eventTitle, name]);
        } else {
            // Prospect-typed attendee. If this head is really an existing customer
            // (converted prospect, or name/phone match), count them under Customer
            // so the same person is never reported as a prospect too.
            const prosp = prospMap[entityId];
            const name = prosp?.full_name || att.entity_name || '—';
            const isCustomer = convertedProspectIds.has(String(entityId)) ||
                _matchesCustomer(prosp?.full_name || att.entity_name, prosp?.phone);
            if (isCustomer) customerRows.push([date, eventTitle, name]);
            else prospectRows.push([date, eventTitle, name]);
        }
        byEvent[eventTitle] = (byEvent[eventTitle] || 0) + 1;
    }

    return _renderActivityHeadcount(customerRows, prospectRows, agentRows, byEvent);
};

// Shared render for buildActivityHeadcountDetails — the legacy client scan builds
// customerRows/prospectRows/agentRows/byEvent, then renders here. Customer and
// Prospect are separate buckets; a head counted as a customer is never also a
// prospect (the builder reclassifies such rows into customerRows).
const _renderActivityHeadcount = (customerRows, prospectRows, agentRows, byEvent) => {
    const customerCount = customerRows.length;
    const prospectCount = prospectRows.length;
    const agentCount = agentRows.length;

    const summaryByEvent = Object.keys(byEvent).length
        ? `<div style="background:#f5f3ff;border:1px solid #ddd6fe;border-radius:6px;padding:12px 16px;margin-bottom:14px;">
             <div style="font-size:12px;color:var(--gray-500);margin-bottom:8px;font-weight:600;">By Event:</div>
             ${Object.entries(byEvent).sort((a,b) => b[1]-a[1]).map(([name, c]) => `<div style="display:flex;justify-content:space-between;padding:4px 0;font-size:13px;"><span>${escapeHtml(name)}</span><strong>${c} attendee${c===1?'':'s'}</strong></div>`).join('')}
           </div>`
        : '';

    const badge = (n, label, bg, border, color) => `
        <div style="background:${bg};border:1px solid ${border};border-radius:6px;padding:10px 16px;flex:1;text-align:center;">
            <div style="font-size:20px;font-weight:700;color:${color};">${n}</div>
            <div style="font-size:12px;color:var(--gray-500);">${label}</div>
        </div>`;
    const countBadge = `<div style="display:flex;gap:12px;margin-bottom:14px;">
        ${badge(customerCount, 'Customer', '#dcfce7', '#86efac', '#166534')}
        ${badge(prospectCount, 'Prospect', '#e0f2fe', '#7dd3fc', '#0369a1')}
        ${badge(agentCount, 'Agent', '#fef3c7', '#fcd34d', '#92400e')}
    </div>`;

    const section = (title, count, rows, cols) => `<div style="margin-bottom:18px;">
        <h4 style="font-size:14px;font-weight:600;margin-bottom:8px;">${title} (${count})</h4>
        ${renderDetailTable(cols, rows)}
    </div>`;

    return countBadge + summaryByEvent
        + section('Customer Attendees', customerCount, customerRows, ['Date', 'Event', 'Attendee'])
        + section('Prospect Attendees', prospectCount, prospectRows, ['Date', 'Event', 'Attendee'])
        + section('Agent Attendees', agentCount, agentRows, ['Date', 'Event', 'Agent']);
};

const showKPIDetails = async (key) => {
    const ranges = getDateRanges(_currentTimeFilter, _customDateFrom, _customDateTo);
    const { from, to } = ranges.current;
    const titles = {
        cpsCount: 'CPS Consultations',
        totalSales: 'Total Sales',
        popCaseCount: 'POP Cases',
        eppCaseCount: 'EPP Cases',
        activeAgents: 'Active Agents (60-day)',
        newAgents: 'New Agents',
        newCustomers: 'New Customers',
        conversionRate: 'Conversion Rate',
        totalMeetings: 'Meetings & Training',
        clientMeetings: 'Client Meetings',
        neaPitching: 'NEA Pitching',
        fengshuiPitching: 'Fengshui Pitching',
        activityHeadcount: 'Activity Attendance',
        meetUpExistingCount: 'Meet Up (Existing Customers)',
        cfHeadcount: 'CF Headcount (CPS Referrers)',
        agentHours: 'Agent Operating Hours (This Week)'
    };
    const title = titles[key] || 'Details';

    const filterStrip = `
        <div style="background:var(--gray-50,#f7f4ed);padding:10px 14px;border-radius:6px;margin-bottom:14px;font-size:12px;color:var(--gray-500);">
            <strong>Date range:</strong> ${from} to ${to}
            &nbsp;·&nbsp; <strong>Role filter:</strong> ${_currentRoleFilter}
            ${_visibleUserIds !== 'all' ? ' &nbsp;·&nbsp; <strong>Scoped to your team</strong>' : ''}
        </div>`;

    UI.showModal(title + ' — Breakdown',
        filterStrip + '<div style="text-align:center;padding:24px;color:var(--gray-400);"><i class="fas fa-spinner fa-spin"></i> Loading details...</div>',
        [{ label: 'Close', type: 'primary', action: 'UI.hideModal()' }],
        'fullscreen');

    let body;
    try {
        if (key === 'cpsCount')              body = await buildCPSDetails(from, to);
        else if (key === 'totalSales')       body = await buildTotalSalesDetails(from, to);
        else if (key === 'popCaseCount')     body = await buildPOPDetails(from, to);
        else if (key === 'eppCaseCount')     body = await buildEPPCasesDetails(from, to);
        else if (key === 'activeAgents')     body = await buildActiveAgentsDetails();
        else if (key === 'newAgents')        body = await buildNewAgentsDetails(from, to);
        else if (key === 'newCustomers')     body = await buildNewCustomersDetails(from, to);
        else if (key === 'conversionRate')   body = await buildConversionDetails(from, to);
        else if (key === 'totalMeetings')    body = await buildMeetingsDetails(from, to);
        else if (key === 'clientMeetings')   body = await buildClientMeetingsDetails(from, to);
        else if (key === 'neaPitching')      body = await buildNeaPitchingDetails(from, to);
        else if (key === 'fengshuiPitching') body = await buildFengshuiPitchingDetails(from, to);
        else if (key === 'activityHeadcount')  body = await buildActivityHeadcountDetails(from, to);
        else if (key === 'meetUpExistingCount') body = await buildMeetUpExistingDetails(from, to);
        else if (key === 'cfHeadcount')        body = await buildCFHeadcountDetails(from, to);
        else if (key === 'agentHours')         body = await buildAgentHoursDetails();
        else body = '<p>No details available for this metric.</p>';
    } catch (e) {
        console.error('showKPIDetails error', e);
        body = '<p style="color:#dc2626;padding:16px;">Failed to load details. See console for error.</p>';
    }

    // Re-render modal with loaded body
    UI.showModal(title + ' — Breakdown',
        filterStrip + body,
        [{ label: 'Close', type: 'primary', action: 'UI.hideModal()' }],
        'fullscreen');
};

    // Shared base card definitions — single source of truth for BOTH the legacy
    // HTML grid (renderKPIStats) and the React JSX grid payload (_buildKpiCards),
    // so the two paths can never drift in label/value/order/icon/color.
    const _kpiCardDefs = (kpis, prevKpis) => {
        const eppDetails = (kpis.eppDetails || []).map(d => ({ bank: d.bank, months: d.months, count: d.count }));
        return [
            { label: 'CPS Consultations', value: kpis.cpsCount, prev: prevKpis.cpsCount, icon: '📞', color: 'blue', key: 'cpsCount' },
            { label: 'Total Sales', value: `RM ${kpis.totalSales.toLocaleString()} `, prev: prevKpis.totalSales, icon: '💰', color: 'green', key: 'totalSales' },
            { label: 'POP Cases', value: kpis.popCaseCount, prev: prevKpis.popCaseCount, icon: '📦', color: 'orange', key: 'popCaseCount',
              subType: 'pop', popTotal: (kpis.popSales || 0).toLocaleString(),
              subHtml: `<div style="font-size:12px;color:var(--gray-500);margin-top:2px;">RM ${(kpis.popSales || 0).toLocaleString()} total</div>` },
            { label: 'EPP Cases', value: kpis.eppCaseCount, prev: prevKpis.eppCaseCount, icon: '💳', color: 'purple', key: 'eppCaseCount',
              subType: 'epp', eppDetails,
              subHtml: (kpis.eppDetails || []).length > 0
                ? (kpis.eppDetails || []).map(d => `<div style="font-size:11px;color:var(--gray-500);line-height:1.6;">${escapeHtml(d.bank)} &middot; ${escapeHtml(d.months)} months &times;${escapeHtml(d.count)}</div>`).join('')
                : '' },
            { label: 'Active Agents', value: kpis.activeAgents || 0, prev: prevKpis.activeAgents || 0, icon: '⚡', color: 'green', key: 'activeAgents',
              subType: 'active',
              subHtml: `<div style="font-size:12px;color:var(--gray-500);margin-top:2px;">Past 60 days · click for team breakdown</div>` },
            { label: 'New Agents', value: kpis.newAgents, prev: prevKpis.newAgents, icon: '👤', color: 'blue', key: 'newAgents' },
            { label: 'New Customers', value: kpis.newCustomers, prev: prevKpis.newCustomers, icon: '👥', color: 'green', key: 'newCustomers' },
            { label: 'Conversion Rate', value: `${kpis.conversionRate}% `, prev: prevKpis.conversionRate, icon: '📈', color: 'purple', key: 'conversionRate' },
            { label: 'Meetings & Training', value: kpis.totalMeetings, prev: prevKpis.totalMeetings, icon: '📅', color: 'orange', key: 'totalMeetings' },
            { label: 'Client Meetings', value: kpis.clientMeetings, prev: prevKpis.clientMeetings, icon: '🤝', color: 'blue', key: 'clientMeetings' },
            { label: 'NEA Pitching', value: kpis.neaPitching || 0, prev: prevKpis.neaPitching || 0, icon: '🧧', color: 'orange', key: 'neaPitching' },
            { label: 'Fengshui Pitching', value: kpis.fengshuiPitching || 0, prev: prevKpis.fengshuiPitching || 0, icon: '🧭', color: 'green', key: 'fengshuiPitching' },
            { label: 'Activity Attendance', value: kpis.activityHeadcount, prev: prevKpis.activityHeadcount, icon: '📊', color: 'purple', key: 'activityHeadcount' },
            { label: 'Agent Hours (Wk)', value: kpis.agentHours, prev: prevKpis.agentHours, icon: '⏱️', key: 'agentHours',
              color: (kpis.agentHoursPct >= 90 ? 'green' : kpis.agentHoursPct >= 60 ? 'orange' : 'red') }
        ];
    };

    // Per-card derived trend fields (identical math to the legacy inline block).
    const _kpiCardTrend = (c, kpis, prevKpis) => {
        const cur = kpis[c.key];
        // Some cards (e.g. Agent Hours "45 / 90h") carry a display STRING, not a
        // number — a %-trend against it is meaningless (string math → NaN, which
        // the old code silently rendered as a fake "0% ▲ vs last period"). Flag
        // these so both render paths omit the trend badge entirely.
        if (typeof cur !== 'number' || !isFinite(cur)) {
            return { trendClass: '', trendIcon: '', trendAbs: 0, trendHide: true };
        }
        const diff = c.prev > 0 ? ((cur - prevKpis[c.key]) / prevKpis[c.key] * 100).toFixed(1) : (cur > 0 ? '100' : '0');
        return {
            trendClass: diff >= 0 ? 'trend-up' : 'trend-down',
            trendIcon: diff >= 0 ? 'fa-arrow-up' : 'fa-arrow-down',
            trendAbs: Math.abs(diff),
            trendHide: false,
        };
    };

    // JSX-ready KPI cards payload for the React grid. Pre-computes every derived
    // field so ReportsView stays a pure 1:1 render of renderKPIStats's HTML.
    // Throws are caught by the caller → fall back to the legacy by-id fill.
    const _buildKpiCards = (kpis, prevKpis) =>
        _kpiCardDefs(kpis, prevKpis).map(c => {
            const t = _kpiCardTrend(c, kpis, prevKpis);
            return {
                key: c.key, label: c.label, value: c.value, icon: c.icon, color: c.color,
                definition: KPI_DEFINITIONS[c.key] || '',
                trendClass: t.trendClass, trendIcon: t.trendIcon, trendAbs: t.trendAbs, trendHide: t.trendHide,
                subType: c.subType || null,
                popTotal: c.popTotal,
                eppDetails: c.eppDetails || [],
            };
        });

    const renderKPIStats = (kpis, prevKpis, force = false) => {
        // React owns #kpi-stats-grid when the grid kill-switch is on — the grid
        // is fed via opts.data + a React re-mount (handled in refreshKPIDashboard),
        // NOT by-id innerHTML. Never write into the React-owned node here. The
        // `force` arg is used ONLY by the re-mount-failure fallback, where React
        // has bailed and the node is plain DOM again.
        if (_reactKpiGridOn() && !force) return;
        const grid = document.getElementById('kpi-stats-grid');
        if (!grid) return;

        const cards = _kpiCardDefs(kpis, prevKpis);

        grid.innerHTML = cards.map(c => {
            const t = _kpiCardTrend(c, kpis, prevKpis);

            return `
                <div class="stat-card stat-card-clickable" onclick="app.showKPIDetails('${c.key}')" title="Click to view breakdown">
                    <div class="stat-info">
                        <h3>
                            ${c.label}
                            <div class="kpi-tooltip" onclick="event.stopPropagation();">
                                <i class="fas fa-info-circle"></i>
                                <span class="tooltip-text">${KPI_DEFINITIONS[c.key] || ''}</span>
                            </div>
                        </h3>
                        <div class="stat-value">${c.value}</div>
                        ${c.subHtml || ''}
                        ${t.trendHide ? '' : `<div class="stat-trend ${t.trendClass}">
                            <i class="fas ${t.trendIcon}"></i>
                            <span>${t.trendAbs}% vs last period</span>
                        </div>`}
                    </div>
                    <div class="stat-icon ${c.color}">
                        ${c.icon}
                    </div>
                </div>
            `;
        }).join('');
    };
// Pure HTML-string builder for the yearly target overview card. Extracted
// verbatim from renderTargetOverview's container.innerHTML — it reads only the
// pre-computed `year` and the already-built `rows` array. All async row-building
// (sales totals, progress math) stays in the orchestrator above.
const _buildTargetOverviewHtml = (year, rows) => `
        <div class="targets-card">
            <div class="targets-header">
                <h2>${year} Target Overview</h2>
            </div>
            <div class="perf-table-scroll">
            <table class="targets-table no-card-mode">
                <thead>
                    <tr>
                        <th scope="col">Quarter</th>
                        <th scope="col">CPS Target</th>
                        <th scope="col">Sales Target</th>
                        <th scope="col">Progress</th>
                    </tr>
                </thead>
                <tbody>
                    ${rows.join('')}
                </tbody>
            </table>
            </div>
        </div>
    `;
const renderTargetOverview = async () => {
    const container = document.getElementById('target-overview-container');
    if (!container) return;

    const year = new Date().getFullYear();
    const quarterlyTargets = await AppDataStore.getAll('quarterly_targets');
    const qTargets = quarterlyTargets.filter(t => t.year === year);

    // Compute the four quarters' actual sales in ONE parallel batch (they're
    // independent). Previously each iteration awaited _trySalesTotal serially — four
    // RTTs, or four whole-table scans offline — on every dashboard refresh. Fetch the
    // client fallback base ONCE and share it across quarters that need it.
    let _purchaseBase = null;
    const quarters = await Promise.all([1, 2, 3, 4].map(async (q) => {
        const target = qTargets.find(t => t.quarter === q) || {};
        const qStart = `${year}-${((q - 1) * 3 + 1).toString().padStart(2, '0')}-01`;
        const qEnd = `${year}-${(q * 3).toString().padStart(2, '0')}-${new Date(year, q * 3, 0).getDate()}`;

        let actualSales = await _trySalesTotal(qStart, qEnd);
        if (actualSales === null) {
            // Scoped client fallback: resolve each purchase's agent via its customer
            // (purchases has no agent column) and keep only the viewer's visible set,
            // mirroring getTotalSales so an agent never sums org-wide actuals.
            if (!_purchaseBase) _purchaseBase = await _getPurchaseBase();
            const { purchases, customerMap, userMap } = _purchaseBase;
            actualSales = 0;
            for (const p of purchases) {
                if (p.date < qStart || p.date > qEnd || p.is_agent_package) continue;
                if (!_passesPurchaseFilter(p, _getPurchaseAgentId(p, customerMap), userMap)) continue;
                actualSales += p.amount || 0;
            }
        }
        return { q, target, actualSales };
    }));

    // Build rows in Q1..Q4 order.
    const rows = quarters.map(({ q, target, actualSales }) => {
        const progress = target.total_sales_target ? Math.min(100, (actualSales / target.total_sales_target * 100)) : 0;
        const statusColor = progress > 90 ? 'green' : (progress > 70 ? 'yellow' : (progress > 0 ? 'red' : 'gray'));

        return `
            <tr>
                <td>Q${q}</td>
                <td>${target.cps_count_target || 0}</td>
                <td>RM ${(target.total_sales_target || 0).toLocaleString()}</td>
                <td>
                    <div class="target-progress">
                        <div class="progress-bar-bg">
                            <div class="progress-bar-fill progress-${statusColor}" style="width: ${progress}%"></div>
                        </div>
                        <span style="font-size: 12px; font-weight: 600;">${progress > 0 ? progress.toFixed(0) + '%' : '0%'}</span>
                    </div>
                </td>
            </tr>
        `;
    });

    container.innerHTML = _buildTargetOverviewHtml(year, rows);
};


    // Pure HTML-string builder for the quarterly performance breakdown cards.
    // Extracted verbatim from renderPerformanceTable's container.innerHTML — it
    // reads only the pre-computed `metrics` array (all per-card derived math
    // stays inside the .map()). No awaits / no DOM mutation here.
    const _buildPerformanceTableHtml = (metrics) => `
            <div class="perf-card-list">
                ${metrics.map(m => {
                    const variance = m.actual - m.target;
                    const achievement = m.target > 0 ? (m.actual / m.target * 100) : 0;
                    const statusClass = achievement > 90 ? 'success' : (achievement > 70 ? 'warning' : 'danger');
                    const statusIcon = achievement > 90 ? '🟢' : (achievement > 70 ? '🟡' : '🔴');
                    const prefix = m.isRM ? 'RM ' : '';
                    const varStr = m.isRM
                        ? (variance >= 0 ? '+RM ' : '-RM ') + Math.abs(variance).toLocaleString()
                        : (variance >= 0 ? '+' : '') + variance.toLocaleString();
                    return `
                        <div class="perf-metric-card">
                            <div class="perf-metric-name">${m.name}</div>
                            <div class="perf-metric-stats">
                                <div class="perf-stat-pair">
                                    <span class="perf-stat-lbl">Target</span>
                                    <span class="perf-stat-val">${prefix}${m.target.toLocaleString()}</span>
                                </div>
                                <div class="perf-stat-pair">
                                    <span class="perf-stat-lbl">Actual</span>
                                    <span class="perf-stat-val">${prefix}${m.actual.toLocaleString()}</span>
                                </div>
                                <div class="perf-stat-pair">
                                    <span class="perf-stat-lbl">Variance</span>
                                    <span class="perf-stat-val" style="color:${variance >= 0 ? 'var(--success)' : 'var(--error)'}">${varStr}</span>
                                </div>
                                <div class="perf-stat-pair">
                                    <span class="perf-stat-lbl">Achievement</span>
                                    <span class="status-badge-${statusClass}">${achievement.toFixed(1)}% ${statusIcon}</span>
                                </div>
                            </div>
                        </div>
                    `;
                }).join('')}
            </div>
        `;

    const renderPerformanceTable = async (kpis) => {
        const container = document.getElementById('quarterly-performance-table');
        if (!container) return;

        // kpis is pre-computed by refreshKPIDashboard; fall back to computing
        // it here only when this function is called in isolation (e.g. tests).
        if (!kpis) {
            const ranges = getDateRanges('quarterly');
            kpis = await calculateKPIs(ranges.current.from, ranges.current.to);
        }
        const year = new Date().getFullYear();
        const quarter = Math.floor(new Date().getMonth() / 3) + 1;
        const qTarget = (await AppDataStore.getAll('quarterly_targets')).find(t => t.year === year && t.quarter === quarter) || {};

        const metrics = [
            { name: 'CPS Count', target: qTarget.cps_count_target || 0, actual: kpis.cpsCount },
            { name: 'Total Sales', target: qTarget.total_sales_target || 0, actual: kpis.totalSales, isRM: true },
            { name: 'New Agents', target: qTarget.new_agents_target || 0, actual: kpis.newAgents },
            { name: 'New Customers', target: qTarget.new_customers_target || 0, actual: kpis.newCustomers },
            { name: 'POP Cases', target: qTarget.pop_case_count_target || 0, actual: kpis.popCaseCount },
            { name: 'EPP Cases', target: qTarget.epp_case_count_target || 0, actual: kpis.eppCaseCount },
            { name: 'Meet Up (Existing Customers)', target: qTarget.meetup_existing_target || 0, actual: kpis.meetUpExistingCount || 0 },
            { name: 'CF Headcount', target: qTarget.cf_headcount_target || 0, actual: kpis.cfHeadcount || 0 }
        ];

        container.innerHTML = _buildPerformanceTableHtml(metrics);
    };


const renderAgentLeaderboard = async () => {
    const container = document.getElementById('agent-leaderboard-table');
    if (!container) return;

    let agentsList = (await AppDataStore.getAll('users')).filter(isAgent);
    if (_visibleUserIds !== 'all') {
        agentsList = agentsList.filter(u => _visibleUserIds.includes(u.id));
    }
    if (_currentRoleFilter !== 'All') {
        agentsList = agentsList.filter(u => u.role === _currentRoleFilter);
    }
    const ranges = getDateRanges(_currentTimeFilter, _customDateFrom, _customDateTo);

    // ── Per-agent sales (current + previous period) ────────────────────────
    // Resolve each purchase's agent via its customer's responsible_agent_id —
    // purchases has NO agent_id column, so the old `p.agent_id === agent.id`
    // match was ALWAYS false and this leaderboard always rendered zero. Try the
    // server aggregation first (one grouped pass, scalable); on any guard/RPC
    // error fall back to a CORRECTED client computation (same customer-based
    // resolution). Either path now produces the right numbers.
    const salesByAgent = new Map(); // String(agentId) -> { current, prev }
    const _lbScopeIds = (_visibleUserIds === 'all' || !Array.isArray(_visibleUserIds))
        ? null
        : _visibleUserIds.map(v => Number(v)).filter(n => Number.isFinite(n));
    try {
        const rows = await AppDataStore.agentSalesByPeriod({
            curFrom: ranges.current.from,  curTo: ranges.current.to,
            prevFrom: ranges.previous.from, prevTo: ranges.previous.to,
            visibleAgentIds: _lbScopeIds,
        });
        for (const r of rows) {
            salesByAgent.set(String(r.agent_id), {
                current: Number(r.current_sales) || 0,
                prev:    Number(r.prev_sales)    || 0,
            });
        }
    } catch (e) {
        console.warn('[agentLeaderboard] server agg → corrected client fallback:', e?.message || e);
        const [allPurchases, allCustomers] = await Promise.all([
            AppDataStore.getAll('purchases'),
            AppDataStore.getAll('customers'),
        ]);
        const custAgent = new Map(allCustomers.map(c => [String(c.id), c.responsible_agent_id]));
        for (const p of allPurchases) {
            const aid = custAgent.get(String(p.customer_id));
            if (aid == null) continue;
            const key = String(aid);
            let s = salesByAgent.get(key);
            if (!s) { s = { current: 0, prev: 0 }; salesByAgent.set(key, s); }
            if (p.date >= ranges.current.from  && p.date <= ranges.current.to)  s.current += (p.amount || 0);
            if (p.date >= ranges.previous.from && p.date <= ranges.previous.to) s.prev    += (p.amount || 0);
        }
    }

    // Build stats using for...of to avoid async map issues
    const agentStats = [];
    for (const agent of agentsList) {
        const _s = salesByAgent.get(String(agent.id)) || { current: 0, prev: 0 };
        const currentSales = _s.current;
        const prevSales = _s.prev;

        let trend = 'Stable';
        let trendClass = 'warning';
        if (prevSales > 0) {
            const diff = ((currentSales - prevSales) / prevSales * 100);
            trend = (diff >= 0 ? '+' : '') + diff.toFixed(0) + '%';
            trendClass = diff >= 0 ? 'success' : 'danger';
        } else if (currentSales > 0) {
            trend = 'New';
            trendClass = 'success';
        }

        agentStats.push({
            name: agent.full_name,
            team: agent.team || 'General',
            sales: currentSales,
            trend: trend,
            trendClass: trendClass
        });
    }

    agentStats.sort((a, b) => b.sales - a.sales);
    const top10 = agentStats.slice(0, 10);

    if (top10.length === 0) {
        container.innerHTML = '<p style="padding:20px;text-align:center;color:var(--gray-400);">No agent data for this period</p>';
        return;
    }
    container.innerHTML = `
        <div class="lb-list">
            ${top10.map((a, i) => `
                <div class="lb-row">
                    <span class="rank-badge rank-${Math.min(i + 1, 5)}">${i + 1}</span>
                    <div class="lb-agent">
                        <strong>${escapeHtml(a.name)}</strong>
                        <small>${escapeHtml(a.team)}</small>
                    </div>
                    <span class="lb-sales">RM ${a.sales.toLocaleString()}</span>
                    <span class="status-badge-${a.trendClass} lb-trend">${a.trend}</span>
                </div>
            `).join('')}
        </div>
    `;
};

    const renderRevenueChart = async (filter, range) => {
        const ctx = document.getElementById('revenue-trend-chart');
        if (!ctx) return;
        await window._ensureChartJs();

        if (_revenueChart) _revenueChart.destroy();

        let labels = [];
        let actualData = [];
        let targetData = [];

        // TZ-stable parse of a Supabase 'YYYY-MM-DD' date string. `new Date(str)`
        // parses as UTC midnight, so .getMonth()/.getDay() read the LOCAL date and
        // roll back a day in negative-UTC offsets, mis-bucketing boundary sales.
        // Parse the parts manually (local date) so month/quarter/day are stable.
        const _ymd = (s) => {
            const [y, m, d] = String(s).split('-').map(Number);
            return { month: (m || 1) - 1, jsDay: new Date(y, (m || 1) - 1, d || 1).getDay() };
        };

        const year = new Date().getFullYear();
        const yTarget = (await AppDataStore.getAll('yearly_targets')).find(t => t.target_year === year) || {};
        const qTargets = (await AppDataStore.getAll('quarterly_targets')).filter(t => t.year === year);

        if (filter === 'weekly') {
            labels = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
            const dayMap = { 0: 6, 1: 0, 2: 1, 3: 2, 4: 3, 5: 4, 6: 5 }; // Sunday is 0 in JS
            actualData = [0, 0, 0, 0, 0, 0, 0];

            const _byDay = await _trySalesByDay(range.from, range.to);
            if (_byDay) {
                _byDay.forEach(r => {
                    const day = _ymd(r.sale_date).jsDay;
                    actualData[dayMap[day]] += (Number(r.total) || 0);
                });
            } else {
                const currentWeekPurchases = (await AppDataStore.getAll('purchases')).filter(p =>
                    p.date >= range.from && p.date <= range.to && !p.is_agent_package
                );
                currentWeekPurchases.forEach(p => {
                    const day = _ymd(p.date).jsDay;
                    actualData[dayMap[day]] += (p.amount || 0);
                });
            }

            const weeklyTarget = (yTarget.total_sales_target || 0) / 52;
            targetData = Array(7).fill(weeklyTarget / 7);
        } else if (filter === 'monthly') {
            labels = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
            actualData = Array(12).fill(0);
            targetData = Array(12).fill(0);

            const _byDay = await _trySalesByDay(`${year}-01-01`, `${year}-12-31`);
            if (_byDay) {
                _byDay.forEach(r => {
                    const month = _ymd(r.sale_date).month;
                    actualData[month] += (Number(r.total) || 0);
                });
            } else {
                const yearPurchases = (await AppDataStore.getAll('purchases')).filter(p =>
                    // Null-safe: some purchase rows carry a null `date` (RPC NULL-date
                    // parity note), and p.date.startsWith would throw on those.
                    p.date && p.date.startsWith(year.toString()) && !p.is_agent_package
                );
                yearPurchases.forEach(p => {
                    const month = _ymd(p.date).month;
                    actualData[month] += (p.amount || 0);
                });
            }

            // Distribute quarterly targets to months
            qTargets.forEach(qt => {
                const mBase = (qt.quarter - 1) * 3;
                const mTarget = (qt.total_sales_target || 0) / 3;
                targetData[mBase] = mTarget;
                targetData[mBase + 1] = mTarget;
                targetData[mBase + 2] = mTarget;
            });
        } else if (filter === 'quarterly') {
            labels = ['Q1', 'Q2', 'Q3', 'Q4'];
            actualData = Array(4).fill(0);
            targetData = [0, 0, 0, 0];

            const _byDay = await _trySalesByDay(`${year}-01-01`, `${year}-12-31`);
            if (_byDay) {
                _byDay.forEach(r => {
                    const quarter = Math.floor(_ymd(r.sale_date).month / 3);
                    actualData[quarter] += (Number(r.total) || 0);
                });
            } else {
                const yearPurchases = (await AppDataStore.getAll('purchases')).filter(p =>
                    // Null-safe: some purchase rows carry a null `date` (RPC NULL-date
                    // parity note), and p.date.startsWith would throw on those.
                    p.date && p.date.startsWith(year.toString()) && !p.is_agent_package
                );
                yearPurchases.forEach(p => {
                    const quarter = Math.floor(_ymd(p.date).month / 3);
                    actualData[quarter] += (p.amount || 0);
                });
            }

            qTargets.forEach(qt => {
                targetData[qt.quarter - 1] = qt.total_sales_target || 0;
            });
        } else {
            // Custom range - aggregate by day
            const start = new Date(range.from);
            const end = new Date(range.to);
            const days = Math.floor((end - start) / (24 * 60 * 60 * 1000)) + 1;

            labels = [];
            actualData = Array(days).fill(0);

            const _byDay = await _trySalesByDay(range.from, range.to);
            let _dayTotals = _byDay ? new Map(_byDay.map(r => [r.sale_date, Number(r.total) || 0])) : null;
            // De-quad fallback: bucket purchases by day ONCE (sum amount||0 per
            // p.date, RAW key + strict === parity, non-agent-package prefilter) so
            // the per-day fill is O(1) instead of a full-array .filter+.reduce per
            // day (was O(days × purchases)). Built lazily only when the RPC fast
            // path is unavailable.
            if (!_dayTotals) {
                const _allPurchases = await AppDataStore.getAll('purchases');
                _dayTotals = new Map();
                for (const p of _allPurchases) {
                    if (p.is_agent_package) continue;
                    const k = p.date; // RAW key
                    _dayTotals.set(k, (_dayTotals.get(k) || 0) + (p.amount || 0));
                }
            }
            for (let i = 0; i < days; i++) {
                const d = new Date(start);
                d.setDate(start.getDate() + i);
                const dStr = d.toISOString().split('T')[0];
                labels.push(dStr.split('-').slice(1).join('/'));

                actualData[i] = _dayTotals.get(dStr) || 0;
            }

            const dailyTarget = (yTarget.total_sales_target || 0) / 365;
            targetData = Array(days).fill(dailyTarget);
        }

        _revenueChart = new Chart(ctx, {
            type: 'line',
            data: {
                labels: labels,
                datasets: [
                    {
                        label: 'Actual Sales',
                        data: actualData,
                        borderColor: 'var(--primary)',
                        backgroundColor: 'rgba(13, 148, 136, 0.1)',
                        fill: true,
                        tension: 0.4
                    },
                    {
                        label: 'Target Sales',
                        data: targetData,
                        borderColor: '#94a3b8',
                        borderDash: [5, 5],
                        fill: false,
                        tension: 0.4
                    }
                ]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        mode: 'index',
                        intersect: false,
                        callbacks: {
                            label: function (context) {
                                return context.dataset.label + ': RM ' + context.parsed.y.toLocaleString();
                            }
                        }
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        ticks: {
                            callback: function (value) {
                                if (value >= 1000000) return 'RM ' + (value / 1000000).toFixed(1) + 'M';
                                if (value >= 1000) return 'RM ' + (value / 1000).toFixed(0) + 'K';
                                return 'RM ' + value;
                            },
                            maxTicksLimit: 6
                        }
                    },
                    x: {
                        ticks: { maxRotation: 0, autoSkipPadding: 8 }
                    }
                }
            }
        });
    };

